parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "assistant_reply": {
      "type": "string",
      "description": "The conversational text reply to the user. Use markdown formatting."
    },
    "widgets": {
      "type": "array",
      "description": "Array of UI widgets. Use empty array [] if no visual is needed.",
      "items": {
        "type": "object",
        "properties": {
          "type": { "type": "string", "enum": ["chart", "image", "triage_action"] },
          "chart_type": { "type": "string", "enum": ["line", "multi_line", "bar", "stacked_bar", "area", "donut", "scatter", "radar", "gauge", "heatmap"] },
          "title": { "type": "string" },
          "x_axis_label": { "type": "string" },
          "y_axis_label": { "type": "string" },
          "data": { "type": "array", "items": { "type": "object" } },
          "value": { "type": "number", "description": "For gauge charts: the current value" },
          "min": { "type": "number", "description": "For gauge charts: minimum scale value" },
          "max": { "type": "number", "description": "For gauge charts: maximum scale value" },
          "target": { "type": "number", "description": "For gauge charts: target value" },
          "url": { "type": "string" },
          "alt_text": { "type": "string" },
          "action_text": { "type": "string" },
          "button_label": { "type": "string" }
        },
        "required": ["type", "title"]
      }
    }
  },
  "required": ["assistant_reply", "widgets"]
}
